//BlockComment : ('/*' ('*/'! .)* '*/')
static BOOL blockComment_rule(ClipperExpressionParser * parser)
{
   YAPP_NODE * lastNode = parser->currentNode;
   INT32 startIndex;
   BOOL match;
   BOOL lastRuleIsAtomic = parser->currentRuleIsAtomic;
   if (parser->blockComment_ruleMemoStart == parser->index)
   {
      if (parser->blockComment_ruleMemoStart <= parser->blockComment_ruleMemoEnd)
      {
         parser->index = parser->blockComment_ruleMemoEnd;
         if (! parser->currentRuleIsAtomic)
         {
            parser->currentNode = createNode(parser, &CLIPPEREXPRESSION_BLOCK_COMMENT, parser->blockComment_ruleMemoStart, parser->blockComment_ruleMemoEnd, FALSE, FALSE);
            lastNode->sibling = parser->currentNode;
            if (parser->blockComment_ruleMemoFirstNode != NULL)
            {
               parser->currentNode->firstChild = parser->blockComment_ruleMemoFirstNode->firstChild;
            }
         }
         return TRUE;
      } else {
         return FALSE;
      }
   }
   parser->currentRuleIsAtomic = TRUE;
   startIndex = parser->index;
   // ('/*' ('*/'! .)* '*/')
   // '/*'
   match = stringMatcher(parser, "/*", 2);
   if (match)
   {
      // ('*/'! .)*
      {
         YAPP_NODE * lastNode_1;
         INT32 lastIndex_1;
         do {
            lastNode_1 = parser->currentNode;
            lastIndex_1 = parser->index;
            // ('*/'! .)
            // '*/'!
            // '*/'
            match = stringTest(parser, "*/", 2);
            match = ! match;
            if (match)
            {
               // .
               match = anyCharMatcher(parser);
            }
         } while(match);
         lastNode_1->sibling = NULL;
         parser->currentNode = lastNode_1;
         parser->index = lastIndex_1;
         match = TRUE;
      }
      if (match)
      {
         // '*/'
         match = stringMatcher(parser, "*/", 2);
      }
   }
   if (match)
   {
      parser->currentRuleIsAtomic = lastRuleIsAtomic;
      parser->blockComment_ruleMemoStart = startIndex;
      parser->blockComment_ruleMemoEnd = parser->index;
      if (parser->currentRuleIsAtomic)
      {
         parser->blockComment_ruleMemoFirstNode = NULL;
      } else {
         parser->currentNode = createNode(parser, &CLIPPEREXPRESSION_BLOCK_COMMENT, startIndex, parser->index, FALSE, FALSE);
         lastNode->sibling = parser->currentNode;
         parser->blockComment_ruleMemoFirstNode = parser->currentNode;
      }
      return TRUE;
   } else {
      parser->currentRuleIsAtomic = lastRuleIsAtomic;
      parser->blockComment_ruleMemoStart = startIndex;
      parser->blockComment_ruleMemoEnd = -1;
      parser->blockComment_ruleMemoFirstNode = NULL;
      parser->index = startIndex;
      lastNode->sibling = NULL;
      parser->currentNode = lastNode;
      return FALSE;
   }
}

//EndStmt : ('\n' | '\r\n' | ';')
static BOOL endStmt_rule(ClipperExpressionParser * parser)
{
   YAPP_NODE * lastNode = parser->currentNode;
   INT32 startIndex;
   BOOL match;
   BOOL lastRuleIsAtomic = parser->currentRuleIsAtomic;
   parser->currentRuleIsAtomic = TRUE;
   startIndex = parser->index;
   // ('\n' | '\r\n' | ';')
   {
      switch(yapp_buffer_getChar(parser->buffer, parser->index)) {
         case ';': {
            ++parser->index;
            // <EMPTY>
            match = TRUE;
            break;
         }
         case '\r': {
            ++parser->index;
            // '\n'
            if (match = yapp_buffer_matchChar(parser->buffer, parser->index, '\n'))
            {
               ++parser->index;
            }
            break;
         }
         case '\n': {
            ++parser->index;
            // <EMPTY>
            match = TRUE;
            break;
         }
         default: {
            match = FALSE;
         }
      }
   }
   if (match)
   {
      parser->currentRuleIsAtomic = lastRuleIsAtomic;
      if (! parser->currentRuleIsAtomic)
      {
         parser->currentNode = createNode(parser, &CLIPPEREXPRESSION_END_STMT, startIndex, parser->index, FALSE, FALSE);
         lastNode->sibling = parser->currentNode;
      }
      return TRUE;
   } else {
      parser->currentRuleIsAtomic = lastRuleIsAtomic;
      parser->index = startIndex;
      lastNode->sibling = NULL;
      parser->currentNode = lastNode;
      return FALSE;
   }
}

